window.__QUIZ_DATA__=[{"id":"theory>Chemistry>2003>1>a","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"a","group":"","topic":"PERIODIC CHEMISTRY : PERIODICITY OF THE ELEMENTS","question":"The electronic configuration of five elements represented by the letters P, Q, R, S and T are indicated below.  P - 1s2 2s2 2p2  R- 1s2 2s2 2p6  T - 1s2 2s2 2p6 3s2 3p5  Q - 1s2 2s2 2p4  S - 1s2 2s2 2p6 3s2  Without identifying the elements, which of them  i. belongs to group VI in the periodic table  ii. is strongly metallic in character  iii. readily ionizes by gaining one electron  iv. contains two unpaired electrons in the ground state atom  v. readily losses two eletrons during chemical bonding  vi. does not participate readily in chemical reactions  vii. is an s-block element","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"P - 1s2 2s2 2p2  R- 1s2 2s2 2p6  T - 1s2 2s2 2p6 3s2 3p5  Q - 1s2 2s2 2p4  S - 1s2 2s2 2p6 3s2    i. It has 6 electrons in its outermost shell, which is shell L i.e 2, 6 (K and L shells respectively).  [Q]    ii. Metals have high tendency of loosing their electrons to become stable. S can easily loose its two outmost electrons.  [S]    iii. T has 7 valence electrons. It needs only one electron left to attain its octet configuration. Therefore it readily ionizes by gaining one electron.    iv. Using Hund's rule of maximum multiplicity    As seen in the degenerate orbital 2P, two electrons are not paired.  [Q]    v. See 1(a) (ii)  [S]    vi. Element R has an octet configuration. Its valence shell can accommodate maximum of 8 electrons and the shell is completely filled.  Elements which have their outmost shell completely filled i.e group O elements, do not participate readily in chemical reactions.         vii. It belongs to S-block since its valence electron is in S-block i.e 3s2.  [S]","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2003>1>b>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Copy and complete the table below as appropriate  ParticleNumber of protonsNumber of ElectronsNumber of Neutrons11H112713Al3+168O-28","images":[],"marking_scheme":"ParticleNumber of protonsNumber of electronsNumber of neutrons11H    2713Al3+    168O2-1    13    81    10    100    14    8","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2003>1>b>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : PERIODIC LAW","question":"Give the reason why atomic radius increase down a group in the periodic table but decreases from left to right in a period.","images":[],"marking_scheme":"Atomic radius increases down the group and decreases from left to right because electrons and protons are added, te large nuclear charge exert the strong attraction upon the electrons around it and this tends to pull them towards the radius.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2003>1>c>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.","question":"What is meant by the half-life of a radioactive element?","images":[],"marking_scheme":"Half life is the time taken for half of the total number of atoms of the radioactive nucleus to disintegrate.","marks":"3","difficulty":"1"},{"id":"theory>Chemistry>2003>1>c>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"The nuclide 21084Po loses an alpha particle to form lead. Write an equation for the reaction.","images":[],"marking_scheme":"21084Po \u2192 20682Pb + 42He  An alpha particle is Helium nucleus represented as 42He.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>1>d>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.","question":"State the type of chemical bonding which accounts for this observations:    Chlorine exists as discrete molecules","images":[],"marking_scheme":"Covalent bonding in chlorine results in the formation of discrete Cl2 molecules, where each molecule is electrically neutral and consists of two chlorine atoms bonded together.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>1>d>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"State the type of chemical bonding which accounts for this observations:  Sodium chloride dissolves readily in water","images":[],"marking_scheme":"Ionic bond exist between aggregate of ions. When NaCl is dissolved in water, Na+ is attracted to oxygen side of water, while the Cl- is attracted to hydrogen side of the water molecule.  This causes the sodium chloride to split in water.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>1>d>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL BONDS : COORDINATE (DATIVE) COVALENT BONDING.","question":"State the type of chemical bonding which accounts for this observations:  CuSO4(aq) forms a deep blue complex ion with excess NH3(aq)","images":[],"marking_scheme":"In dative bond, only one participant donates the shared pair electrons. At the end of the reaction, a dark blue copper ammine complex ion [Cu(NH3)2+4] is formed.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>2>a>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.","question":"State three characteristic properties of transition metals.","images":[],"marking_scheme":"Properties of Transition Metals  - They show variable oxidation states.  - They form coloured ions and compounds.  - They have high melting and boiling points.  - They form compounds which are often paramagnetic.  - They have partially filled d-orbitals.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>2>a>ii>I","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"I","group":"FINAL","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"What is the oxidation state of manganese in each of the following species?    - MnCl2","images":[],"marking_scheme":"MnCl2  Oxidation number of Cl is -1  Mn + (-1 \u00d7 2) = 0  Mn - 2 = 0  Mn = +2","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>2>a>ii>II","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"II","group":"FINAL","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"What is the oxidation state of manganese in each of the following species?  - MnO2","images":[],"marking_scheme":"MnO2  Oxidation number of O is -2  n + (-2 \u00d7 2) = 0  Mn - 4 = 0  Mn = +4","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>2>a>ii>III","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"III","group":"FINAL","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"What is the oxidation state of manganese in each of the following species?  MnO4-","images":[],"marking_scheme":"MnO4-  Mn + (-2 \u00d7 4) = -1  Mn - 8 = -1  Mn = -1 + 8  Mn = +7","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>2>a>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL BONDS : METALLIC BONDING","question":"Explain why manganese conducts electricity in the solid state but manganese chloride conducts only when molten or in solution.","images":[],"marking_scheme":"Manganese is a metal and is thus a good conductor of electricity due to its metallic bonding. Manganese chloride is a salt ionically bonded and thus conducts electrically in solution when it ionizes or when in molten form.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>2>b>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"The collision theory suggests that for two particles to react, they must collide. What two factors determine whether or not the collision would lead to formation of products?","images":[],"marking_scheme":"- The particles must collide such that they posses energy equal or greater than the activation energy.  - The particles must collide in the right orientation.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>2>b>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"","topic":"ENERGY AND ENERGY CHANGES : ENERGY AND ENTHALPY","question":"Use an energy profile diagram to illustrate what is meant by the enthalpy chang (\u0394H) and the activation energy (EA) of a reaction.","images":["data:image/png;base64,"],"marking_scheme":"Ea - Activation energy  A + B is the reactant  C is the product  HP is the heat content of the product  HR is the heat content of the reactant  \u0394H = HP - HR","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>2>c>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"When few drops of aqueous KSCN are added to a solution of iron (III) salt, the following equilibrium is setup:  Fe3+(aq) + 3SCN-(aq) \u21cc Fe(SCN)3(aq)  yellow &nbsp &nbsp &nbsp colourless &nbsp &nbsp &nbsp deep red    The equilibrium mixture has a pale red colour    Explain what would happen if more KSCN(aq) were added to the equilibrium mixture.","images":[],"marking_scheme":"If more of KSCN(aq) were added to the equilibrium mixture, the equilibrium position will shift to the right, using some of the additional reactants and produce more of Fe(SCN)3(aq).  Therefore, the solution becomes a darker red colour because of the increase in the concentration of Fe(SCN)3(aq)","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>2>c>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"When few drops of aqueous KSCN are added to a solution of iron (III) salt, the following equilibrium is setup:  Fe3+(aq) + 3SCN-(aq) \u21cc Fe(SCN)3(aq)  yellow &nbsp &nbsp &nbsp colourless &nbsp &nbsp &nbsp deep red    The equilibrium mixture has a pale red colour  Which of the ions in the equilibrium mixture forms an insoluble hydroxide with NaOH(aq)? Write an equation for the reaction.","images":[],"marking_scheme":"The ion that forms an insoluble hydroxide with NaOH(aq) is Fe3+.  Equation:  Fe3+(aq) + 3NaOH(aq) \u2192 Fe(OH)3(s) + 3Na+(aq)  Hydroxide salts of transition metals are insoluble.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>2>c>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"When few drops of aqueous KSCN are added to a solution of iron (III) salt, the following equilibrium is setup:  Fe3+(aq) + 3SCN-(aq) \u21cc Fe(SCN)3(aq)  yellow &nbsp &nbsp &nbsp colourless &nbsp &nbsp &nbsp deep red    The equilibrium mixture has a pale red colour  State two changes observed on adding NaOHaq to the equilibrium mixture.","images":[],"marking_scheme":"- There is formation of a gelatinous precipitate which is insoluble in excess NaOH(aq)  - The colour changes to Yellow.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>3>a>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"An organic compound X contains 40% carbon. 6.67% hydrogen, the rest being oxygen. If X has a relative molecular mass of 60, determine its empirical formula.    [H = 1, C = 12, O = 16]","images":[],"marking_scheme":"40% Carbon &nbsp &nbsp 6.67% hydrogen    Oxygen (100% - [40% + 6.6%]) = 53.33%  CHONumber of mole40/126.67/153.33/163.336.673.33Simplest mole ratio   3.33/3.33    16.67/3.33    23.33/3.33    1    \u2234 Emperical formula = CH2O","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2003>3>a>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"An organic compound X contains 40% carbon. 6.67% hydrogen, the rest being oxygen. If X has a relative molecular mass of 60, determine its molecular formula.    [H = 1, C = 12, O = 16]","images":[],"marking_scheme":"Relative molecular mass, RMM = 60  n(CH2O) = 60  n(12 + [1 \u00d7 2] + 16) = 60  n(12 + 2 + 16) = 60  n(30) = 60  n=6030  n = 2  Molecular formula = 2(CH2O)  C2H4O2","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>3>b>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS","question":"An alkanoic acid Y has a relative molecular mass of 74.  State the functional group of Y.","images":[],"marking_scheme":"Relative molecular mass, RMM of an alkanoic acid Y = 74;  Functional group: - COOH","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>3>b>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOATES AS DRIVATIVES OF ALKANOIC ACIDS","question":"An alkanoic acid Y has a relative molecular mass of 74.  What type of reaction is involved when Y is converted to an alkanoate?","images":[],"marking_scheme":"Esterification: This is a reaction between an alkanoic acid and an alkanol to form ester (alkanoate) and water.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>3>b>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"An alkanoic acid Y has a relative molecular mass of 74.  Determine the structural formula of Y","images":["data:image/png;base64,"],"marking_scheme":"An alkanoic acid has a general molecular formula of CnH2n + 1COOH.  Firstly, we need to know the member of the alkanoic acid we are dealing with.  (CnH2n + 1COOH) = 74  12 \u00d7 n + 1(2n + 1) + 12 + 16 + 16 + 1 = 74  12n + 2n + 1 + 45 = 74  14n = 74 - 46  14n = 28  n=2814  n = 2  C2H2(2) + 1COOH  C2H4 + 1COOH  C2H5COOH  The molecular formular has three carbon atoms including the one in the functional group. Hence, the name is propanoic acid.    Carbon is tetravalent, hence, there must be four bonds around carbon. One bond for hydrogen and two bonds for oxygen.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>3>b>iv","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANOIC ACIDS","question":"An alkanoic acid Y has a relative molecular mass of 74  Write an equation for the reaction between Y and sodium.","images":[],"marking_scheme":"2C2H5COOH + 2Na \u2192 2C2H5COONa + H2  Sodium displaced the hydrogen in -COOH to form C2H5COONa and liberate hydrogen gas.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>3>b>v","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"An alkanoic acid Y has a relative molecular mass of 74  If X in (a) above boils at 118\u00b0C and belongs to the same homologous series as Y, state with reason whether the boiling point of Y will be equal to, higher or lower than 118\u00b0C.","images":[],"marking_scheme":"The boiling point of Y will be higher than that of X because Y has higher number of carbon atoms. The density of members of a homologous series increases as the number of carbons increase, this will lead to increase in their boiling point.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>3>c>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES","question":"What is fermentation?","images":[],"marking_scheme":"Fermentation is a slow degradation or decomposition process whereby large carbohydrate molecules, such as starch or sugar are broken down into smaller molecules such as alcohol through the agency of enzymes produced by micro-organisms such as yeast.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>3>c>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES","question":"Write an equation for the fermentation of glucose.","images":[],"marking_scheme":"C6H12O6 (Glucose) \u2192 2C2H5OH (ethanol) + 2CO2 + Energy  (In the presence of Zymase)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>3>c>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : CARBOHYDRATES","question":"What must be added to glucose solution to make it ferment?","images":[],"marking_scheme":"Yeast contains enzyme zymase which breaks down the glucose to ethanol and carbon dioxide.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>3>c>iv","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : BIOTECHNOLOGY","question":"Explain why a tightly corked glass bottle filled to the brim with fresh palm wine shatters on standing.","images":[],"marking_scheme":"The bottle shatters upon standing due to the pressure built up by the carbon IV oxide released by the fermentation process.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2003>4>a>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"Give two reasons why aluminium is preferred to copper for making overhead electric cables.","images":[],"marking_scheme":"- Aluminium is cheaper than copper.  - Aluminium is lighter than copper.  - It's stronger at the same price point.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2003>4>a>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"Describe briefly the electrolytic extraction of aluminium from purified bauxite.","images":[],"marking_scheme":"Aluminium ore called bauxite (Al2O3) is first melted so that electricity can pass through it, though it has a very high melting point which is expensive to melt. Instead, it is dissolved in molten cryolite which has a lower melting point. Both the negative and positive electrodes are made of graphite. Aluminium ions receive electrons at the negative electrodes and reduced to aluminium atoms.  Al3+ + 3e- \u2192 Al  The molten aluminium sinks to the bottom of the cell, where it is trapped off. Oxides ions lose electrons at the positive electrodes and are oxidized to oxygen gas.  2O2- \u2192 O2 + 4e-","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2003>4>b>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The diagram below represents an eletrolytic cell used for the purification of copper.      Which of the electrodes I and II increases in mass during the electrolysis?, Give reasons for your answers.","images":["data:image/png;base64,"],"marking_scheme":"Electrode I  Reason: The positive electrode of cell is usually connected to the anode (impure copper) and the negative electrode of the cell is connected to the cathode (pure copper). The anode dissolves in the solution and deposited at the cathode as pure copper, hence, the increase in mass of electrode I.","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2003>4>b>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The diagram below represents an eletrolytic cell used for the purification of copper.    State with reason the site of oxidation.","images":["data:image/png;base64,"],"marking_scheme":"Oxidation takes place at the anode i.e electrode II, which involves loss of electron. The copper is dissolved at the anode (electrode II) by oxidation by losing two electrons to become copper ion (Cu2+) and then go into the solution  Cu(s) \u2192 Cu2+(aq) + 2e-","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2003>4>b>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"The diagram below represents an eletrolytic cell used for the purification of copper.    Identify III and explain why its colour does not change in intensity during the electrolysis.","images":["data:image/png;base64,"],"marking_scheme":"III is the electrolyte which is copper II tetraoxosulphate VI solution. Its colour does not change in intensity because it is the copper which dissolves in the solution that is deposited at electrode I. Therefore, there is no change in the concentration of the electrolyte.","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2003>4>c","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"c","group":"FINAL","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Calculate the current in amperes that will deposit 8.00g of calcium from fused CaCl2 in 1 hour 15 minutes.  [Ca = 40.0, 1 Faraday = 96500C]    Leave your answer in two decimal places 'a.bcA'","images":[],"marking_scheme":"For calcium to be deposited, it must gain two electrons  Ca2+(aq) + 2e- \u2192 Ca(s)  2e- will deposit 40g of calcium  But 1e- = 96500C  \u2234 2 \u00d7 96500 ........................  40g  y ........................ 8g  y=2 \u00d7 96500 \u00d7 840  y = 38600C  But, Q = It  t = 1hr 15min = 60 min + 15 min = 75min  \u21d2 (75 \u00d7 60)s  \u21d2 4500s  \u2234 38600 = I \u00d7 4500  I=386004500  I = 8.58A","marks":"5","difficulty":"3"},{"id":"theory>Chemistry>2003>5>a>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : OXYGEN","question":"Mention one oxide in each case, which is used in bleaching.","images":[],"marking_scheme":"Sulphur IV oxide (SO2)  SO2 dissolves in water to form trioxosulphate VI acid. Its bleaching ability is due to its strong reducing power.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>5>a>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : OXYGEN","question":"Mention one oxide in each case, which is a reddish-brown gas.","images":[],"marking_scheme":"Nitrogen IV oxide (NO2)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>5>a>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Mention one oxide in each case, which reacts with NaOH and also with HCl.","images":[],"marking_scheme":"Amphoteric oxide such as Al2O3.  Amphoteric oxide are oxides of metals which behave like an acid when reacting with base, and also behave like a base when reacting with an acid.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>5>a>iv","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : BASES","question":"Mention one oxide in each case, which dissolves in water to give a solution with pH greater than 7.","images":[],"marking_scheme":"Copper II oxide (CuO), Sodium oxide (Na2O)  A solution with pH greater than 7 is basic. Hence, CuO, Na2O react with water to form a base.","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2003>5>a>v","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"Mention one oxide in each case, which oxidizes hot, concentrated HCl to chlorine.","images":[],"marking_scheme":"Manganese IV oxide (MnO2)  MnO2 reacts with hot concentrated HCl to produce mangane chloride (MnCl2), water and chlorine gas.  MnO2 + 4HCl \u2192 MnCl2 + Cl2 + 2H2O","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>5>b>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION","question":"State three methods that can be used to remove hardness in a sample of water that contains calcium hydrogentrioxocarbonate (IV).","images":[],"marking_scheme":"- Boiling  Ca(HCO3)2 \u2192 CaCO3 + CO2 + H2O  (in the presencec of Heat)    - Treatment with base  Mg(HCO3)2 + Ca(OH)2 \u2192 CaCO3 + MgCO3 + 2H2O    - Addition of Borax, Na2B4O7.10H2O","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>2003>5>b>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Explain with the aid of appropriate equation, why it is not advisable to build a house with limestone in an environment polluted by sulphur (IV) oxide.","images":[],"marking_scheme":"An environment polluted by sulphur IV oxide forms acid rain which can dissolve limestone.  SO2 + H2O \u2192 H2SO3  2H2SO3 + O2 \u2192 2H2SO4  H2SO4 + CaCO3 \u2192 CaSO4 + CO2 + H2O","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>5>c>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"List two compounds of potassium which yield oxygen when heated strongly.","images":[],"marking_scheme":"- Potassium trioxochlorate V, KClO3  2KClO3(s) + heat \u2192 2KCl(s) + 3O2(g)    - Trioxonitrate V acid, KNO3  2KNO3 + heat \u2192 2KNO2 + O2","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>5>c>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Calculate the amount (in moles) of gas which occupies 250cm3 s.t.p.  [1 mole of gas occupies 22.4 dm3 at s.t.p.]    Leave your answer in three decimal places 'a.bcd'","images":[],"marking_scheme":"1 mole of a gas at s.t.p = 22.4dm3 = 22400cm3  1 mole = 22400cm3  x = 250cm3  x=25022400  x = 0.011mole","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2003>5>c>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"FINAL","topic":"STATES OF MATTER : GASES","question":"If 250 cm3 of a gas at s.t.p. is heated to 27\u00b0C at constant pressure, calculate its new volume.    Leave your answer in one decimal place 'a.'","images":[],"marking_scheme":"V1 = 250cm3, T1 = 27 + 273 = 300K  V2 = ?  Standard temperature, T2 = 273K  Using Charles' law  V1T1=V2T2  250300=V2273  V2=250 \u00d7 273300  V2 = 227.5cm3","marks":"3","difficulty":"3"},{"id":"theory>Chemistry>2003>5>c>iv","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Explain in terms of the collision theory what happens as a gas is heated at constant pressure.","images":[],"marking_scheme":"When a gas is heated at constant pressure, the molecules acquire more kinetic energy which make them to move faster, thereby increasing their rate of collision, which would also increase the pressure. If the dimensions of the container is increased (increase in volume), the pressure generated is kept constant.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>6>a>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State the role of each of this substance in the treatment of river water for town supply.    Sand Bed.","images":[],"marking_scheme":"Sand Bed - This serves as a filter to remove the suspended particles.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>6>a>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State the role of each of this substance in the treatment of river water for town supply.  Alum","images":[],"marking_scheme":"Alum - This is used for coagulation. It attracts the fine particles and suspended materials in the water and settles down at the bottom of the water.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>6>a>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State the role of each of this substance in the treatment of river water for town supply.  Chlorine.","images":[],"marking_scheme":"Chlorine - This is added to kill germs or any micro-organism present in the water.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>6>b>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give three major use of H2SO4.","images":[],"marking_scheme":"Uses of H2SO4  - It is used in the production of fertilizers.  - For the manufacture of chemicals e.g HCl.  - It is as dehydrating agent.  - It is used as electrolyte.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>6>b>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Explain the following observation: A strip of blue litmus paper dropped into concentrated H2SO4 becomes charred whereas in dilute H2SO4 it turns red and is not charred.","images":[],"marking_scheme":"The concentrated H2SO4 has a strong affinity for water, thereby dehydrating the litmus paper, leaving only carbon behind. The dilute H2SO4 does not completely dehydrate the water in the litmus paper. It only turns it red.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>6>b>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Write an equation to show how concentrated H2SO4 reacts with zinc.","images":[],"marking_scheme":"Conc. 2H2SO4 + Zn \u2192 ZnSO4 + SO2 + 2H2O  Concentrated H2SO4 on reaction with metals produce salt, water and the product of reduction of sulphur while dil. H2SO4 only form zinc sulphate and hydrogen gas.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>6>c>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"List two gaseous pollutants that can be generated by burning coal.","images":[],"marking_scheme":"- Nitrogen IV oxide (NO2)  - Sulphur IV oxide (SO2)","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2003>6>c>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"Explain why coal burns more easily when it is broken into pieces than when it is in lump form.","images":[],"marking_scheme":"The coal burns more easily when broken into pieces than when it is in lump form because the oxygen which is needed for the combustion is in contact with larger surface area when in broken form than in lump form.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2003>6>c>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"What gas is responsible for most of the explosions in coal mines?","images":[],"marking_scheme":"Methane gas  This explosions occur when methane, which is a by-product of coal comes in contact with heat source.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>6>c>iv","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : CARBON","question":"Name the non-volatile residue left behind after the destructive distillation of coal.","images":[],"marking_scheme":"Coal tar.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2003>6>d>i","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"What is meant by allotropy?","images":[],"marking_scheme":"Allotropy is a phenomenon which explains the existence of a substance in two or more different forms, in the same physical state.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>6>d>ii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"Name two crystalline allotropes of carbon.","images":[],"marking_scheme":"Allotropes of Carbon (crystalline forms)  - Diamond  - Graphite","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2003>6>d>iii","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"Name two elements apart from carbon which exhibit allotropy.","images":[],"marking_scheme":"- Sulphur (Rhombic and Monoclinic)  - Phosphorus (white and red)  - Tin (White and Red)  - Oxygen (Oxygen and Ozone)","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2003>6>d>iv","subject":"Chemistry","year":"2003","type":"Theory","sub_label":"iv","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"It is now known that carbon has an allotropic form called fullerene, containing molecules of formula C60. Calculate the mass of one mole of these molecules.   [C = 12]    Leave your answer in whole number 'abc'","images":[],"marking_scheme":"number of mole, n = ?  mass, m = ?  Molar mass, MM = 12 \u00d7 60 = 720  Recall,  n=mMM  m = n \u00d7 MM  m = 1 \u00d7 720  m = 720g","marks":"2","difficulty":"3"}];